command:
agent-browser --session-name phase11-safe-grinder eval "(() => {
  const save = JSON.parse(window.localStorage.getItem('jones_fastlane_save') || '{}');
  const session = window.__JONES_FASTLANE_SESSION__ || {};
  return {
    location: document.querySelector('[data-testid=\"active-location-label\"]')?.innerText || 'Unknown',
    credits: session.credits || save.credits,
    hunger: session.hunger || save.hunger,
    sanity: session.sanity || save.sanity,
    turn: session.turn || save.turn,
    hasPendingTurnSummary: !!document.querySelector('[data-testid=\"turn-summary-modal\"]')
  };
})()" --no-sandbox

